function solve(n, edges, label) {
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }
    let maxLen = 1;

    function dfs(current, mask, path) {
        // Check if current path is a palindrome
        let isPalindrome = true;
        const len = path.length;
        for (let i = 0; i < len / 2; i++) {
            if (path[i] !== path[len - 1 - i]) {
                isPalindrome = false;
                break;
            }
        }
        if (isPalindrome) {
            maxLen = Math.max(maxLen, len);
        }

        // Explore neighbors
        for (const neighbor of adj[current]) {
            const newMask = mask | (1 << neighbor);
            if ((mask & (1 << neighbor)) === 0) {
                const newPath = [...path, label[neighbor]];
                dfs(neighbor, newMask, newPath);
            }
        }
    }

    for (let i = 0; i < n; i++) {
        const initialMask = 1 << i;
        const initialPath = [label[i]];
        dfs(i, initialMask, initialPath);
    }

    return maxLen;
}
